css:
body {
  color: #1f2937;
}

.euer-header {
  border-bottom: 2px solid #1f2937;
  margin-bottom: 18px;
  padding-bottom: 10px;
}

.euer-title {
  font-size: 22px;
  font-weight: 700;
  margin: 0 0 4px;
  letter-spacing: 0.02em;
  text-transform: uppercase;
}

.euer-subtitle {
  font-size: 13px;
  color: #4b5563;
  margin: 0;
}

.euer-meta {
  width: 100%;
  border-collapse: collapse;
  margin: 14px 0 18px;
}

.euer-meta td {
  padding: 4px 8px 4px 0;
  vertical-align: top;
  font-size: 12px;
}

.euer-label {
  width: 90px;
  color: #6b7280;
  text-transform: uppercase;
  font-size: 11px;
  letter-spacing: 0.04em;
}

.euer-summary {
  width: 100%;
  border: 1px solid #cbd5e1;
  border-collapse: collapse;
  margin: 18px 0 22px;
}

.euer-summary td {
  padding: 9px 10px;
  font-size: 12px;
}

.euer-summary tr + tr td {
  border-top: 1px solid #e5e7eb;
}

.euer-summary td:last-child {
  text-align: right;
  font-weight: 700;
  white-space: nowrap;
}

.euer-summary .result td {
  border-top: 2px solid #1f2937;
  font-size: 13px;
  font-weight: 700;
}

.euer-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 8px;
  font-size: 12px;
}

.euer-table th,
.euer-table td {
  padding: 7px 8px;
  border-bottom: 1px solid #d1d5db;
}

.euer-table thead th {
  border-top: 1px solid #1f2937;
  border-bottom: 1px solid #1f2937;
  font-size: 11px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.euer-right {
  text-align: right;
  white-space: nowrap;
}

.euer-table tr.section td {
  padding-top: 14px;
  border-bottom: 0;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.euer-table tr.total td {
  font-weight: 700;
  border-top: 1px solid #9ca3af;
}

.euer-table tr.result td {
  font-weight: 700;
  border-top: 2px solid #1f2937;
  border-bottom: 2px solid #1f2937;
}

.euer-signature {
  margin-top: 42px;
  width: 100%;
}

.euer-signature td {
  width: 50%;
  padding-right: 28px;
  vertical-align: bottom;
}

.euer-line {
  border-top: 1px solid #6b7280;
  padding-top: 6px;
  font-size: 11px;
  color: #6b7280;
}
